// Expo config plugin: accent press-feedback ripple for the agenda widget's tap
// targets. react-native-android-widget's clickable overlay ships with
// ?selectableItemBackground — a barely visible gray — so we override the
// library layout at the app level (app-module resources win over library
// resources at merge time) and point it at a brand ripple.
//
// These files can't live in the repo directly: android/ is gitignored and
// regenerated by `expo prebuild` locally and in CI. They also can't live in
// the RNAW patch: bun's patch applier fails on patches that create files in
// new directories (EACCES on mkdir, seen with bun 1.2.x on 2026-07-15).
const { withDangerousMod } = require('expo/config-plugins');
const fs = require('fs');
const path = require('path');

const RIPPLE_DRAWABLE = `<?xml version="1.0" encoding="utf-8"?>
<!-- Press feedback for widget tap targets: brand accent (#FFBD4F) at 12% alpha,
     masked to the house 4dp corner radius. Written by
     plugins/with-widget-ripple.js — edit there, not here. -->
<ripple xmlns:android="http://schemas.android.com/apk/res/android"
    android:color="#1FFFBD4F">
    <item android:id="@android:id/mask">
        <shape android:shape="rectangle">
            <solid android:color="@android:color/white" />
            <corners android:radius="4dp" />
        </shape>
    </item>
</ripple>
`;

const CLICKABLE_LAYOUT = `<?xml version="1.0" encoding="utf-8"?>
<!-- Overrides react-native-android-widget's rn_widget_clickable.xml, identical
     to upstream except the background ripple. View ids MUST stay in sync with
     upstream (RNWidget.java references rn_widget_clickable_area by id).
     Written by plugins/with-widget-ripple.js — edit there, not here. -->
<FrameLayout xmlns:android="http://schemas.android.com/apk/res/android"
    android:id="@+id/rn_widget_clickable_positioner"
    android:layout_width="match_parent"
    android:layout_height="match_parent">

    <FrameLayout
        android:id="@+id/rn_widget_clickable_area"
        android:layout_width="match_parent"
        android:layout_height="wrap_content"
        android:background="@drawable/rn_widget_clickable_ripple"
        android:clickable="true"
        android:focusable="true" />
</FrameLayout>
`;

module.exports = function withWidgetRipple(config) {
  return withDangerousMod(config, [
    'android',
    (cfg) => {
      const res = path.join(
        cfg.modRequest.platformProjectRoot,
        'app',
        'src',
        'main',
        'res'
      );
      fs.mkdirSync(path.join(res, 'drawable'), { recursive: true });
      fs.mkdirSync(path.join(res, 'layout'), { recursive: true });
      fs.writeFileSync(
        path.join(res, 'drawable', 'rn_widget_clickable_ripple.xml'),
        RIPPLE_DRAWABLE
      );
      fs.writeFileSync(
        path.join(res, 'layout', 'rn_widget_clickable.xml'),
        CLICKABLE_LAYOUT
      );
      return cfg;
    },
  ]);
};
